type ReferenceRenderer = (page: StandalonePage & { pageNum: number }) => React.ReactNode;
const DEFAULT_PAGE_FORMAT = { width: 210, height: 297 };

function getPageFlowKey(page: StandalonePage, parent?: PageItem) {
  return parent ? `${parent.id}/${page.id}` : page.id;
}

// Schema-based page option types
export type PageOptionSelectValue = {
  label: string;
  value: string;
  hex?: string; // For color-series options
};

type PageOptionTarget = string | ((pageOrGroup: PageItem) => boolean);

type BasePageOption = {
  id: string;
  label: string;
  description?: string;
  appliesTo?: PageOptionTarget | PageOptionTarget[];
};

export type SelectPageOption = BasePageOption & {
  type: 'select';
  options: PageOptionSelectValue[];
  getValue: (pageOrGroup: PageItem) => string | number | boolean;
  onChange?: (
    pageOrGroupId: string,
    value: string,
    context: { item?: PageItem; updateItem: (patch: Partial<PageItem>) => void }
  ) => void;
  applyPatch?: (value: string, item?: PageItem) => Partial<PageItem> | void;
};

export type TogglePageOption = BasePageOption & {
  type: 'toggle';
  getValue: (pageOrGroup: PageItem) => boolean;
  onChange?: (
    pageOrGroupId: string,
    value: string,
    context: { item?: PageItem; updateItem: (patch: Partial<PageItem>) => void }
  ) => void;
  applyPatch?: (value: string, item?: PageItem) => Partial<PageItem> | void;
};

export type SliderPageOption = BasePageOption & {
  type: 'slider';
  min: number;
  max: number;
  step: number;
  getValue: (pageOrGroup: PageItem) => number;
  onChange?: (
    pageOrGroupId: string,
    value: string,
    context: { item?: PageItem; updateItem: (patch: Partial<PageItem>) => void }
  ) => void;
  applyPatch?: (value: string, item?: PageItem) => Partial<PageItem> | void;
};

export type CounterPageOption = BasePageOption & {
  type: 'counter';
  min: number;
  max: number;
  step: number;
  getValue: (pageOrGroup: PageItem) => number;
  onChange?: (
    pageOrGroupId: string,
    value: string,
    context: { item?: PageItem; updateItem: (patch: Partial<PageItem>) => void }
  ) => void;
  applyPatch?: (value: string, item?: PageItem) => Partial<PageItem> | void;
};

export type ColorSeriesPageOption = BasePageOption & {
  type: 'color-series';
  options: PageOptionSelectValue[]; // Must include hex property
  getValue: (pageOrGroup: PageItem) => string;
  onChange?: (
    pageOrGroupId: string,
    value: string,
    context: { item?: PageItem; updateItem: (patch: Partial<PageItem>) => void }
  ) => void;
  applyPatch?: (value: string, item?: PageItem) => Partial<PageItem> | void;
};

export type PageOption = SelectPageOption | TogglePageOption | SliderPageOption | CounterPageOption | ColorSeriesPageOption;

type PreviewMode = 'single_page' | 'two_pages';

interface PageEditorProps {
  templateConfig: Parameters<typeof buildPageGroupsConfig>[0];
  payload?: any;
  onPayloadChange?: (nextPayload: any) => void;
  pageFormat?: { width: number; height: number; preview?: PreviewMode; bleed?: number; [key: string]: any };
  pageOptions?: Array<PageOption | PayloadOptionDefinition>;
  notifyError?: (message: string) => void;
  referenceRenderer?: ReferenceRenderer;
  renderOverlay?: (args: { pageNo: number; total: number; pageId: string; parent?: PageItem }) => React.ReactNode;
  renderPage?: (args: { page: StandalonePage & { pageNum: number }; parent?: PageItem }) => React.ReactNode;
  menuItems?: React.ReactNode;
  gridColsClass?: string;
  reorderTitle?: string;
  reorderDescription?: string;
  stateKey?: string;
  onItemsChange?: (items: PageItem[], state: PageEditorState) => void;
  onStateChange?: (state: PageEditorState) => void;
  resolveNewItem?: (draft: PageItem) => Promise<PageItem | null | void> | PageItem | null | void;
  pageFilter?: PageFilterConfig; // Filter which pages to render
  printConfigs?: PrintConfigMap; // Unified print configurations (includes filter + pageFormat)
}

function ItemAddedDialog({ label, onDone, onAddAnother }: { label: string | null; onDone: () => void; onAddAnother: () => void }) {
  if (!label) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/30">
      <div className="bg-white rounded-lg border border-gray-200/80 shadow-xl p-6 w-full max-w-sm mx-4 flex flex-col items-center text-center">
        <div className="rounded-full bg-emerald-100 p-3 mb-4">
          <Check className="h-6 w-6 text-emerald-600" strokeWidth={2.5} />
        </div>
        <h2 className="text-base font-medium text-gray-900 mb-5">
          {label} added
        </h2>
        <div className="flex gap-2 w-full">
          <Button variant="outline" size="sm" onClick={onAddAnother} className="flex-1">
            Add another
          </Button>
          <Button variant="default" size="sm" onClick={onDone} className="flex-1">
            Done
          </Button>
        </div>
      </div>
    </div>
  );
}

type PageEditorInnerProps = Omit<PageEditorProps, 'templateConfig'> & {
  initialItems?: PageItem[];
  availableItems?: AvailableItem[];
  pageComponents?: { [pageId: string]: PageComponent };
};

function PageEditorInner({
  initialItems = [],
  availableItems = [],
  pageComponents = {},
  payload,
  pageFormat,
  pageOptions = [],
  notifyError,
  referenceRenderer,
  renderOverlay,
  renderPage,
  menuItems,
  gridColsClass,
  reorderTitle = 'Reorder Pages and Groups',
  reorderDescription = 'Drag and drop to reorder. Groups move as a single unit.',
  stateKey = DEFAULT_PAGE_EDITOR_STATE_KEY,
  onItemsChange,
  onStateChange,
  resolveNewItem,
  pageFilter,
  printConfigs,
}: PageEditorInnerProps) {
  const setup = pageFormat ?? DEFAULT_PAGE_FORMAT;
  const { interactive, setInteractive, enableDevTools } = useInteractive();
  const shouldHideUI = useShouldHideUI();
  
  // Dev print mode state
  const [devFilter, setDevFilter] = useState<PageFilterConfig | null>(null);
  const [devPageFormat, setDevPageFormat] = useState<any>(null);
  const [devSelectedMode, setDevSelectedMode] = useState<string | undefined>(undefined);
  const [devModeTick, setDevModeTick] = useState(0);
  const [devReferenceOpacity, setDevReferenceOpacity] = useState(0);
  
  // Use devFilter if set, otherwise use pageFilter prop
  const effectiveFilter = devFilter ?? pageFilter;
  
  // Apply dev pageFormat overrides if set, otherwise use original pageFormat
  const effectivePageFormat = useMemo(() => {
    if (devPageFormat) {
      return { ...setup, ...devPageFormat };
    }
    return setup;
  }, [setup, devPageFormat]);
  
  // Get payload from context if available (preferred), otherwise use prop
  const templateDataContext = useContext(TemplateDataContext);
  const effectivePayload = templateDataContext?.payload ?? payload;
  const [orderDialogOpen, setOrderDialogOpen] = useState(false);
  const preview: PreviewMode = effectivePageFormat?.preview ?? 'single_page';
  const pageSetup = useMemo(
    () => (preview === 'two_pages' ? { ...effectivePageFormat, preview: 'single_page' } : effectivePageFormat),
    [preview, effectivePageFormat]
  );

  const normalizedItems = useMemo(() => normalizePageItems(initialItems), [initialItems]);
  const resolvedPageOptions = useMemo(() => {
    if (!pageOptions?.length) return [];

    return pageOptions
      .map((option) => {
        if ('getValue' in option) return option;

        if (!templateDataContext?.setPageOptionValue) {
          if (isDev() || enableDevTools) {
            console.warn(
              'PageEditor: payload-backed pageOptions require TemplateDataProvider or payload/onPayloadChange.'
            );
          }
          return null;
        }

        return buildPayloadPageOption(
          option,
          templateDataContext.payload,
          templateDataContext.setPageOptionValue
        );
      })
      .filter(Boolean) as PageOption[];
  }, [pageOptions, templateDataContext]);

  const [lastAddedItem, setLastAddedItem] = useState<AvailableItem | null>(null);
  const [pendingInsertPosition, setPendingInsertPosition] = useState<InsertPosition>({ mode: 'end' });
  const [lastInsertedId, setLastInsertedId] = useState<string | null>(null);
  const highlightTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const {
    items,
    itemsWithPageNum,
    availableItemsToAdd,
    addItem,
    removeItem,
    reorderItems,
    updateItemFields,
    addDialogOpen,
    setAddDialogOpen,
    openAddDialog,
    itemsForReorder,
    handleReorder,
    defaultRenderThumbnail,
  } = usePageGroups({
    initialItems: normalizedItems,
    availableItems,
    pageComponents,
    payload: effectivePayload,
    setup: effectivePageFormat,
    stateKey,
    onItemsChange,
    onStateChange,
    resolveNewItem,
    notifyError,
  });

  type LogicalPageWithParent = LogicalFlowPage;
  type VirtualPageWithParent = VirtualFlowPage<LogicalPageWithParent>;

  const logicalPages = useMemo<LogicalPageWithParent[]>(() => {
    const pages: LogicalPageWithParent[] = [];

    for (const item of itemsWithPageNum) {
      const itemPages = isPageGroup(item)
        ? (item.pages ?? []) as Array<StandalonePage & { pageNum: number }>
        : [item as StandalonePage & { pageNum: number }];

      for (const page of itemPages) {
        if (!page?.id) continue;
        const parentGroup = isPageGroup(item) ? item : undefined;
        pages.push({
          ...page,
          kind: 'page' as const,
          id: page.id,
          pageNum: page.pageNum ?? pages.length + 1,
          basePageNum: page.pageNum ?? pages.length + 1,
          parentGroup,
          flowKey: getPageFlowKey(page, parentGroup),
        });
      }
    }

    return pages.sort((a, b) => (a.basePageNum ?? 0) - (b.basePageNum ?? 0));
  }, [itemsWithPageNum]);

  const flowLayoutKey = useMemo(() => JSON.stringify({
    format: pageSetup?.format,
    orientation: pageSetup?.orientation,
    width: pageSetup?.width,
    height: pageSetup?.height,
    bleed: pageSetup?.bleed,
    showBleed: pageSetup?.showBleed,
    preview: pageSetup?.preview,
    flowPages: logicalPages
      .filter((page) => page.hasFlow)
      .map((page) => page.flowKey)
      .join('|'),
  }), [pageSetup, logicalPages]);

  const logicalTotalPageCount = useMemo(() => getTotalPageCount(items), [items]);

  const {
    allVirtualPages,
    renderedVirtualPages,
    virtualTotalPageCount,
    registerMeasurement: handleFlowMeasurement,
  } = useFlowLayouts<LogicalPageWithParent>({
    logicalPages,
    pageFilter: effectiveFilter,
    layoutKey: flowLayoutKey,
  });

  const renderedVirtualPageIds = useMemo(
    () => new Set(renderedVirtualPages.map((page) => page.virtualPageId)),
    [renderedVirtualPages]
  );

  const measurementOnlyPages = useMemo(
    () => allVirtualPages.filter((page) => (
      page.hasFlow &&
      page.virtualPageIndex === 0 &&
      (renderPage || !renderedVirtualPageIds.has(page.virtualPageId))
    )),
    [allVirtualPages, renderedVirtualPageIds, renderPage]
  );

  // Scroll to newly inserted page after layout settles (Section uses ResizeObserver
  // to calculate scaled height, so the DOM exists immediately but has correct
  // dimensions only after a short delay).
  React.useEffect(() => {
    if (!lastInsertedId) return;
    const timer = setTimeout(() => {
      const el = document.querySelector(`[data-page-item-id="${lastInsertedId}"]`);
      el?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 300);
    return () => clearTimeout(timer);
  }, [lastInsertedId]);

  const buildItemActionHandlers = usePageItemActions({
    items,
    reorderItems,
    availableItemsToAdd,
    setPendingInsertPosition,
    openAddDialog,
  });

  const handleAddItem = useCallback(async (item: AvailableItem) => {
    const result = await addItem(item, pendingInsertPosition);
    if (!result.success) return;

    setLastInsertedId(result.insertedId);
    if (highlightTimerRef.current) clearTimeout(highlightTimerRef.current);
    highlightTimerRef.current = setTimeout(() => setLastInsertedId(null), 1200);

    setPendingInsertPosition({ mode: 'end' });

    if (item.repeatable && item.integration) {
      setLastAddedItem(item);
    }
  }, [addItem, pendingInsertPosition]);

  const getMostVisiblePage = useCallback((): InsertPosition => {
    const pageEls = Array.from(document.querySelectorAll<HTMLElement>('[data-page-item-id]'));
    if (!pageEls.length) return { mode: 'end' };
    const viewportCenter = window.innerHeight / 2;
    let closest: HTMLElement | null = null;
    let closestDist = Infinity;
    for (const el of pageEls) {
      const rect = el.getBoundingClientRect();
      const dist = Math.abs((rect.top + rect.height / 2) - viewportCenter);
      if (dist < closestDist) { closestDist = dist; closest = el; }
    }
    const itemId = closest?.getAttribute('data-page-item-id');
    return itemId ? { mode: 'after', anchorId: itemId } : { mode: 'end' };
  }, []);

  const handleOpenAddDialogFromToolbar = useCallback(() => {
    setPendingInsertPosition(getMostVisiblePage());
    openAddDialog();
  }, [getMostVisiblePage, openAddDialog]);

  const handlePageOptionChange = React.useCallback(
    (pageOption: PageOption, targetItem: PageItem | undefined, value: string) => {
      if (!targetItem) return;

      const patch = pageOption.applyPatch?.(value, targetItem);
      if (patch) {
        updateItemFields(targetItem.id, patch);
      }

      pageOption.onChange?.(targetItem.id, value, {
        item: targetItem,
        updateItem: (patch) => updateItemFields(targetItem.id, patch),
      });
    },
    [updateItemFields]
  );

  const defaultOverlay = (info: { pageNo: number; total: number }) => (
    <div className="absolute bottom-[10mm] left-[15mm] right-[15mm] text-[7pt] text-gray-600 flex items-center justify-between pointer-events-none">
      <span>Page</span>
      <span>
        {info.pageNo} / {info.total}
      </span>
    </div>
  );

  const buildOverlay = (pageNo: number, pageId: string, parent?: PageItem) => {
    if (renderOverlay) {
      return renderOverlay({ pageNo, total: virtualTotalPageCount, pageId, parent });
    }
    return defaultOverlay({ pageNo, total: virtualTotalPageCount });
  };

  const renderPageContent = (
    page: VirtualPageWithParent,
    options: { renderVisible?: boolean; measureFlow?: boolean } = {}
  ) => {
    const parent = page.parentGroup;

    if (renderPage && options.renderVisible !== false) {
      return renderPage({ page, parent });
    }

    const componentKey = page.componentKey ?? page.id;
    const reference = enableDevTools && referenceRenderer ? referenceRenderer(page) : null;
    const effectiveReference =
      enableDevTools && referenceRenderer
        ? (
            React.isValidElement(reference)
              ? React.cloneElement(reference as React.ReactElement<any>, {
                  opacity: devReferenceOpacity,
                })
              : reference
          )
        : null;
    const templateId = page.templateId ?? componentKey;
    const PageComponent = pageComponents[componentKey];
    const pagePayload = templateDataContext?.getPagePayload
      ? templateDataContext.getPagePayload(page)
      : resolvePagePayload(effectivePayload, { id: page.id, templateId, componentKey });
    
    // Resolve integration data using utility function
    // For group pages, prefer parent group's integration; fallback to page's own integration
    const integration = resolveIntegrationForPage(
      effectivePayload,
      page,
      parent
    );

    const dataBinding = buildPageDataBinding({
      payload: effectivePayload,
      page,
      parentGroup: parent,
      pagePayload,
    });

    return (
      <PageCanvas
        key={`${options.renderVisible === false ? 'measure-only' : 'page'}-${page.virtualPageId}`}
        pageId={page.id}
        templateId={templateId}
        pageNo={page.pageNum}
        measurementPageNo={page.basePageNum}
        component={PageComponent}
        payload={effectivePayload}
        pagePayload={pagePayload}
        integration={integration}
        page={page}
        parentGroup={parent}
        componentKey={componentKey}
        setup={pageSetup}
        reference={effectiveReference}
        overlay={({ pageNo }) => buildOverlay(pageNo, page.id, parent)}
        className={page.className}
        dataBinding={dataBinding}
        totalPages={virtualTotalPageCount}
        measurementTotalPages={logicalTotalPageCount}
        flowPageIndex={page.virtualPageIndex}
        flowChunksByFlowId={page.flowChunksByFlowId}
        measureFlow={options.measureFlow ?? (!!page.hasFlow && page.virtualPageIndex === 0)}
        flowMeasurementKey={page.flowKey}
        flowMeasurementVersion={flowLayoutKey}
        onFlowMeasurement={page.hasFlow ? handleFlowMeasurement : undefined}
        renderVisible={options.renderVisible ?? true}
      />
    );
  };

  // Render controls for standalone pages or group pages
  const renderPageControls = (
    page: VirtualPageWithParent,
    parentGroup?: PageItem,
    actionHandlers?: {
      onAddPage?: () => void;
      onMoveUp?: () => void;
      onMoveDown?: () => void;
      onDuplicate?: () => void;
    }
  ) => {
    const isGroupPage = !!parentGroup && isPageGroup(parentGroup);
    const isFirstPageInGroup = isGroupPage && parentGroup.pages[0]?.id === page.id;

    if (page.virtualPageIndex > 0) {
      return (
        <div data-uhuu-editor className="pl-0 pr-3 py-1.5 flex items-center gap-2 h-9">
          <span className="page-number">{page.pageNum}</span>
          <span className="text-xs text-gray-500">
            {(page.label || page.componentKey || page.id)} continued
          </span>
        </div>
      );
    }

    // For group pages, only show controls on the first page (group-level controls)
    if (isGroupPage && !isFirstPageInGroup) {
      return (
        <div className="pl-0 pr-3 py-1.5 flex justify-between items-center h-9">
          <div className="flex items-center gap-2">
            <span className="page-number">
              {page.pageNum}
            </span>
            {page.label && (
              <span className="text-xs text-gray-500">
                {page.label}
              </span>
            )}
            <span className="text-xs text-gray-400">·</span>
          </div>
        </div>
      );
    }

    const targetItem = isGroupPage ? parentGroup : page;
    const displayName = isGroupPage
      ? (parentGroup.label || parentGroup.id)
      : (page.label || `Page ${page.pageNum}`);

    // Group-level controls (for first page in group) or standalone page controls
    return (
      <div className="pl-0 flex items-center h-9">
        <span data-uhuu-editor className="page-number shrink-0 text-xs tabular-nums text-gray-400 font-medium pr-1">{page.pageNum}</span>
        <PageNameDropdown
          name={displayName}
          canRename={true}
          canMoveUp={!!actionHandlers?.onMoveUp}
          canMoveDown={!!actionHandlers?.onMoveDown}
          canAddPage={!!actionHandlers?.onAddPage}
          canDuplicate={!!actionHandlers?.onDuplicate}
          canDelete={logicalTotalPageCount > 1}
          onRename={(val) => updateItemFields(targetItem.id, { label: val || undefined })}
          onMoveUp={actionHandlers?.onMoveUp}
          onMoveDown={actionHandlers?.onMoveDown}
          onAddPage={actionHandlers?.onAddPage}
          onDuplicate={actionHandlers?.onDuplicate}
          onDelete={() => removeItem(targetItem.id)}
        />
        <span className="pl-1">
        {resolvedPageOptions.length > 0 && (
          <PageOptionsDropdown
            pageOptions={resolvedPageOptions}
            targetItem={targetItem}
            onChange={handlePageOptionChange}
            title={isGroupPage ? "Group options" : "Page options"}
          />
        )}
        </span>
      </div>
    );
  };

  type PagePair = {
    left?: VirtualPageWithParent;
    right?: VirtualPageWithParent;
    layout: "spread" | "left" | "right";
  };

  /**
   * Transform origin logic for two-page spreads:
   * - Even pages (2,4,6...) appear on LEFT side → scale from RIGHT edge (gutter)
   * - Odd pages (1,3,5...) appear on RIGHT side → scale from LEFT edge (gutter)
   * This ensures pages meet precisely at center when zoomed
   */
  const pagePairs = useMemo<PagePair[]>(() => {
    if (preview !== 'two_pages') return [];

    const pages = renderedVirtualPages;
    if (!pages.length) return [];
    
    // Page 1 is always alone on the right (cover)
    const pairs: PagePair[] = [{ left: undefined, right: pages[0], layout: "right" }];
    
    // Subsequent pages are paired: 2-3, 4-5, 6-7, etc.
    for (let i = 1; i < pages.length; i += 2) {
      const leftPage = pages[i];
      const rightPage = pages[i + 1];
      
      if (rightPage) {
        pairs.push({ left: leftPage, right: rightPage, layout: "spread" });
      } else {
        // Single page at end: even pages go left, odd pages go right
        const isEven = leftPage.pageNum % 2 === 0;
        pairs.push({
          left: isEven ? leftPage : undefined,
          right: isEven ? undefined : leftPage,
          layout: isEven ? "left" : "right",
        });
      }
    }
    
    return pairs;
  }, [preview, renderedVirtualPages]);

  const defaultMenu = (
    <div className="flex items-center gap-1">
      <Badge variant="secondary" className="font-normal text-xs bg-gray-100/80 text-gray-700 border-0">
        {virtualTotalPageCount} {virtualTotalPageCount === 1 ? 'Page' : 'Pages'}
      </Badge>
      { enableDevTools && (
        <DevPrintControls
          modes={printConfigs}
          selectedMode={devSelectedMode}
          onModeChange={(mode, config) => {
            setDevSelectedMode(mode);
            setDevFilter(config.filter ?? null);
            setDevPageFormat(config.pageFormat ?? null);
            setDevModeTick((v) => v + 1);
          }}
          interactive={interactive}
          onInteractiveChange={(newInteractive) => {
            setInteractive(newInteractive);
            // Reset pageFormat overrides when going back to edit mode
            if (newInteractive) {
              setDevPageFormat(null);
            }
          }}
          hasReferenceRenderer={!!referenceRenderer}
          referenceOpacity={devReferenceOpacity}
          onReferenceOpacityChange={setDevReferenceOpacity}
        />        
      )}      
      {interactive && (
        <>
          {availableItemsToAdd.length > 0 && (
          <Button
            variant="ghost"
            size="sm"
            onClick={handleOpenAddDialogFromToolbar}
            title="Add page or group"
            className="text-xs font-medium text-gray-700 hover:bg-gray-100/80 h-7 px-2.5"
          >
            <Plus className="w-3.5 h-3.5" />
            Add
          </Button>
          )}
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setOrderDialogOpen(true)}
            title="Reorder pages and groups using drag and drop"
            className="text-xs font-medium text-gray-700 hover:bg-gray-100/80 h-7 px-2.5"
          >
            <ClipboardList className="w-3.5 h-3.5" />
            Reorder
          </Button>
        </>
      )}
    </div>
  );

  return (
    <>
      {measurementOnlyPages.map((page) => (
        renderPageContent(page, {
          renderVisible: false,
          measureFlow: true,
        })
      ))}

      {/* Back button when in print mode - always rendered, hidden in print output */}
      {enableDevTools && !interactive && (
        <Button
          onClick={() => setInteractive(true)}
          data-uhuu-editor
          size="sm"
          className="screen-only fixed top-4 right-4 z-50 flex items-center gap-1.5 !text-xs rounded-full"
          title="Back to Edit Mode"
        >
          <X className="w-4 h-4" />
          Back to Editor
        </Button>
      )}
      
      <SectionPageResizer
        key={`dev-mode-${devModeTick}-${devSelectedMode ?? 'default'}`}
        defaultZoom={80}
        minZoom={25}
        maxZoom={200}
        menuItems={menuItems ?? defaultMenu}
        onAddPage={handleOpenAddDialogFromToolbar}
        preview={preview}
      >
        {preview === 'two_pages' ? (
          pagePairs.map((pair, index) => {
            // Anchor IDs for insert position (before = first item in pair, after = last item)
            const firstPage = pair.left ?? pair.right;
            const lastPage = pair.right ?? pair.left;
            const firstAnchorId = (firstPage?.parentGroup as any)?.id ?? firstPage?.id ?? null;
            const lastAnchorId = (lastPage?.parentGroup as any)?.id ?? lastPage?.id ?? null;

            // Highlight if either page in the pair was just inserted
            const leftTopId = (pair.left?.parentGroup as any)?.id ?? pair.left?.id;
            const rightTopId = (pair.right?.parentGroup as any)?.id ?? pair.right?.id;
            const isLeftHighlighted = leftTopId === lastInsertedId;
            const isRightHighlighted = rightTopId === lastInsertedId;

            const getPageHandlers = (page: VirtualPageWithParent | undefined, anchorId: string | null) =>
              buildItemActionHandlers(page ? (page.parentGroup ?? page) as PageItem : undefined, anchorId);

            return (
              <TwoPageSection key={`pair-${index}`} layout={pair.layout} pageItemId={lastAnchorId ?? undefined}>
                {pair.left && (
                  <div
                    data-page-item-id={pair.left.virtualPageIndex === 0 ? leftTopId : undefined}
                    className={isLeftHighlighted ? 'outline outline-2 outline-offset-2 outline-blue-100 bg-blue-50' : undefined}
                  >
                    <Section
                      key={pair.left.virtualPageId}
                      title={`Sheet ${pair.left.pageNum}`}
                      controls={renderPageControls(pair.left, pair.left.parentGroup, getPageHandlers(pair.left, firstAnchorId))}
                      origin={pair.left.pageNum % 2 === 0 ? 'right' : 'left'}
                    >
                      {renderPageContent(pair.left)}
                    </Section>
                  </div>
                )}
                {pair.right && (
                  <div
                    data-page-item-id={pair.right.virtualPageIndex === 0 ? rightTopId : undefined}
                    className={isRightHighlighted ? 'outline outline-2 outline-offset-2 outline-blue-100 bg-blue-50' : undefined}
                  >
                    <Section
                      key={pair.right.virtualPageId}
                      title={`Sheet ${pair.right.pageNum}`}
                      controls={renderPageControls(pair.right, pair.right.parentGroup, getPageHandlers(pair.right, lastAnchorId))}
                      origin={pair.right.pageNum % 2 === 0 ? 'right' : 'left'}
                    >
                      {renderPageContent(pair.right)}
                    </Section>
                  </div>
                )}
              </TwoPageSection>
            );
          })
        ) : (
          renderedVirtualPages.map((page) => {
            const targetItem = (page.parentGroup ?? page) as PageItem;
            const anchorId = page.parentGroup?.id ?? page.id;
            const actionHandlers = buildItemActionHandlers(targetItem, anchorId);
            const topId = page.parentGroup?.id ?? page.id;
            const isHighlighted = lastInsertedId === topId;

            return (
              <div
                key={page.virtualPageId}
                data-page-item-id={page.virtualPageIndex === 0 ? topId : undefined}
                className={isHighlighted ? 'outline outline-2 outline-offset-2 outline-blue-100 bg-blue-50' : undefined}
              >
                <Section
                  title={`Sheet ${page.pageNum}`}
                  controls={renderPageControls(page, page.parentGroup, actionHandlers)}
                >
                  {renderPageContent(page)}
                </Section>
              </div>
            );
          })
        )}
      </SectionPageResizer>

      {interactive && !shouldHideUI && (
        <>
          <AddPageDialog
            open={addDialogOpen}
            onOpenChange={setAddDialogOpen}
            availableItems={availableItemsToAdd}
            onSelectItem={handleAddItem}
            pageComponents={pageComponents}
            payload={effectivePayload}
            setup={setup}
            gridColsClass={gridColsClass}
            data-uhuu-editor
          />

          <PageOrderDialog
            open={orderDialogOpen}
            onOpenChange={setOrderDialogOpen}
            pages={itemsForReorder}
            onReorder={(newOrder) => {
              handleReorder(newOrder);
              setOrderDialogOpen(false);
            }}
            onRemove={(item) => removeItem(item.id)}
            pageComponents={pageComponents}
            payload={effectivePayload}
            setup={setup}
            renderThumbnail={defaultRenderThumbnail}
            title={reorderTitle}
            description={reorderDescription}
            gridColsClass={gridColsClass}
            data-uhuu-editor
          />
        </>
      )}

      <ItemAddedDialog
        label={lastAddedItem ? (lastAddedItem.label ?? lastAddedItem.id) : null}
        onDone={() => setLastAddedItem(null)}
        onAddAnother={() => {
          const item = lastAddedItem;
          setLastAddedItem(null);
          if (item) handleAddItem(item);
        }}
      />
    </>
  );
}

function PageEditorView(props: PageEditorProps) {
  const { templateConfig, ...rest } = props;
  // Check if TemplateDataProvider already exists in the tree
  const existingContext = useContext(TemplateDataContext);
  
  // If context exists, or if no payload/onPayloadChange is provided, render directly
  // Otherwise, wrap with TemplateDataProvider for automatic payload management
  if (existingContext || (!props.payload && !props.onPayloadChange)) {
    return <PageEditorInner {...rest} />;
  }
  
  // Wrap with TemplateDataProvider to enable automatic payload updates
  // Pass stateKey so it can preserve page editor state correctly
  return (
    <TemplateDataProvider 
      payload={props.payload} 
      onPayloadChange={props.onPayloadChange}
      stateKey={props.stateKey}
    >
      <PageEditorInner {...rest} />
    </TemplateDataProvider>
  );
}

export function PageEditor(props: PageEditorProps) {
  const templateDataContext = useContext(TemplateDataContext);
  const effectivePayload = templateDataContext?.payload ?? props.payload;
  
  // Evaluate config with current payload - this re-runs when payload changes
  const resolvedConfig = React.useMemo(
    () => buildPageGroupsConfig({ ...props.templateConfig, payload: effectivePayload }),
    [props.templateConfig, effectivePayload]
  );
  
  const [noticeState, setNoticeState] = React.useState<{ open: boolean; message: string }>({
    open: false,
    message: '',
  });

  const notifyError = React.useCallback((message: string) => {
    setNoticeState({ open: true, message });
  }, []);

  // Read persisted state
  const restoredState = React.useMemo(
    () => readPageEditorState(effectivePayload),
    [effectivePayload]
  );
  
  // Smart state restoration: re-evaluate dynamic groups and preserve user additions
  const restoredItems = React.useMemo(() => {
    if (!restoredState?.items) {
      return resolvedConfig.initialItems;
    }

    // Build a lookup of group definitions (with their original pageComponentKeys functions)
    const rawGroups = props.templateConfig.groups ?? {};
    const groupDefs: any[] = Array.isArray(rawGroups)
      ? rawGroups
      : Object.entries(rawGroups).map(([id, g]: [string, any]) => ({ id, ...g }));
    const groupDefMap = new Map<string, any>(groupDefs.map((g: any) => [g.id, g]));

    // Re-evaluate dynamic pageComponentKeys for every group in persisted state.
    // This keeps user-added groups alive while updating their pages to match
    // the current payload (e.g. sectionLayout change).
    const pagesConfig: Record<string, any> = props.templateConfig.pages ?? {};
    const applyPageTemplateMetadata = (page: any) => {
      const key = page?.componentKey ?? page?.templateId ?? page?.id;
      const template = pagesConfig[key] ?? pagesConfig[page?.templateId] ?? pagesConfig[page?.id];
      if (!template?.hasFlow || page?.hasFlow) return page;
      return { ...page, hasFlow: true };
    };

    const rehydrated = restoredState.items.map((item: PageItem) => {
      if (item.kind !== 'group') return applyPageTemplateMetadata(item);
      const templateId = (item as any).templateId ?? item.id;
      const groupDef = groupDefMap.get(templateId);
      // Re-apply strictPosition from group definition if missing on the persisted item
      const baseItem: PageItem = (groupDef?.strictPosition !== undefined && !(item as any).strictPosition)
        ? { ...item, strictPosition: groupDef.strictPosition } as PageItem
        : item;
      const baseGroupItem = {
        ...(baseItem as any),
        pages: ((baseItem as any).pages ?? []).map(applyPageTemplateMetadata),
      } as PageItem;

      if (!groupDef || typeof groupDef.pageComponentKeys !== 'function') return baseGroupItem;
      try {
        const newKeys: string[] = groupDef.pageComponentKeys({ payload: effectivePayload, item: undefined, parent: undefined });

        // Handle invalid return values
        if (!Array.isArray(newKeys)) {
          console.error(`[PageEditor] pageComponentKeys for group ${baseItem.id} must return an array, got:`, typeof newKeys);
          return baseItem;
        }

        // Handle empty arrays - update to zero pages (intentional hide)
        if (newKeys.length === 0) {
          return {
            ...baseGroupItem,
            pages: [],
          };
        }

        return {
          ...baseGroupItem,
          pages: newKeys.map((key: string, idx: number) => {
            const pageConfig = pagesConfig[key];
            const dataKey = pageConfig?.dataKey;
            return {
              id: `${baseGroupItem.id}__${dataKey ?? key}__${idx}`,
              componentKey: key,
              templateId: key,
              ...(dataKey ? { dataKey } : {}),
              ...(pageConfig?.hasFlow ? { hasFlow: true } : {}),
            };
          }),
        };
      } catch (err) {
        console.error(`[PageEditor] Error evaluating pageComponentKeys for group ${baseGroupItem.id}:`, err);
        return baseGroupItem;
      }
    });

    // Safety check: if the initial-item page counts still differ after rehydration
    // (e.g. a static initial group was added/removed from config), use fresh initial
    // items but preserve any user-added groups at the end.
    const initialItemIds = new Set(resolvedConfig.initialItems.map((i: PageItem) => i.id));
    const rehydratedInitialItems = rehydrated.filter((i: PageItem) => initialItemIds.has(i.id));
    const rehydratedInitialCount = getTotalPageCount(rehydratedInitialItems);
    const freshInitialCount = getTotalPageCount(resolvedConfig.initialItems);

    // If any initial items are missing from persisted state, assume user removed them
    // and preserve the user's edits (do not reintroduce missing initial items).
    const hasMissingInitialItems = Array.from(initialItemIds).some(
      (id) => !rehydratedInitialItems.some((item) => item.id === id)
    );

    if (!hasMissingInitialItems && rehydratedInitialCount !== freshInitialCount) {
      // Only preserve truly user-added groups (where id !== templateId).
      // Initial groups have id === templateId, so they should be re-created from fresh config.
      const addedItems = rehydrated.filter((i: PageItem) => {
        if (i.kind !== 'group') return !initialItemIds.has(i.id);
        const templateId = (i as any).templateId ?? i.id;
        // If id matches templateId, it's an initial group (not user-added)
        return i.id !== templateId && !initialItemIds.has(i.id);
      });

      if (addedItems.length === 0) return resolvedConfig.initialItems;

      // BUG FIX: naively spreading [...initialItems, ...addedItems] places items with
      // strictPosition:'end' (e.g. end_group) before user-added middle items (e.g. listings)
      // because they appear in initialItems first. Re-enforce strictPosition after merging,
      // the same way handleReorder does via enforcePositions in use-page-groups.ts.
      const combined = [...resolvedConfig.initialItems, ...addedItems];
      const startItems = combined.filter((i) => (i as any).strictPosition === 'start');
      const endItems = combined.filter((i) => (i as any).strictPosition === 'end');
      const middleItems = combined.filter((i) => !(i as any).strictPosition);
      return [...startItems, ...middleItems, ...endItems];
    }

    return rehydrated;
  }, [restoredState?.items, resolvedConfig.initialItems, effectivePayload, props.templateConfig.groups, props.templateConfig.pages]);

  return (
    <>
      <PageEditorView
        {...props}
        payload={effectivePayload}
        initialItems={restoredItems}
        availableItems={resolvedConfig.availableItems}
        pageComponents={resolvedConfig.pageComponents}
        notifyError={notifyError}
      />

      <AlertDialog
        open={noticeState.open}
        onOpenChange={(open) => {
          if (!open) {
            setNoticeState({ open: false, message: '' });
          }
        }}
      >
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Cannot remove item</AlertDialogTitle>
            <AlertDialogDescription>
              {noticeState.message}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogAction onClick={() => setNoticeState({ open: false, message: '' })}>
              OK
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

export default PageEditor;
