import * as React from 'react';
import { isDev } from '../utility/is-dev';
import { distributeFlowItems } from './flow-core';

export type StaticFlowItemMeta = {
  breakBefore?: boolean;
  breakAfter?: boolean;
  keepWithNext?: boolean | number;
  avoidBreakInside?: boolean;
  groupKey?: string;
};

export type StaticFlowChunk = {
  indexes: number[];
  keys: string[];
};

export type StaticFlowMeasurement = {
  flowId: string;
  chunks: StaticFlowChunk[];
  signature: string;
};

export type StaticFlowContextValue = {
  mode: 'measure' | 'visible';
  pageIndex: number;
  measurementVersion?: string;
  chunksByFlowId?: Record<string, StaticFlowChunk[]>;
  registerMeasurement?: (measurement: StaticFlowMeasurement) => void;
};

export const StaticFlowContext = React.createContext<StaticFlowContextValue | null>(null);

type FlowAreaProps = {
  children: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
};

const useIsoLayoutEffect = typeof window === 'undefined' ? React.useEffect : React.useLayoutEffect;
const warnedMetaDefaultsWithoutType = new Set<string>();

type FlowItemType<TItem> = TItem extends { type?: infer TType }
  ? Extract<TType, string>
  : string;

type DefaultFlowItemType<TItem> = [FlowItemType<TItem>] extends [never]
  ? string
  : FlowItemType<TItem>;

function getItemType(item: unknown): string | undefined {
  if (!item || typeof item !== 'object' || !('type' in item)) return undefined;
  const type = (item as { type?: unknown }).type;
  return typeof type === 'string' || typeof type === 'number' ? String(type) : undefined;
}

function mergeItemMeta(
  base: StaticFlowItemMeta | undefined,
  override: StaticFlowItemMeta | undefined
): StaticFlowItemMeta {
  const merged: StaticFlowItemMeta = { ...(base ?? {}) };

  for (const [key, value] of Object.entries(override ?? {})) {
    if (value !== undefined) {
      (merged as Record<string, unknown>)[key] = value;
    }
  }

  return merged;
}

function parseKeepWithNext(value: string | undefined): boolean | number {
  if (!value) return false;
  if (value === 'true') return true;

  const count = Number.parseInt(value, 10);
  return Number.isFinite(count) && count > 0 ? count : false;
}

function serializeKeepWithNext(value: StaticFlowItemMeta['keepWithNext']): string | undefined {
  if (typeof value === 'number' && Number.isFinite(value) && value > 0) {
    return String(Math.floor(value));
  }

  return value ? 'true' : undefined;
}

// Compact, allocation-light FNV-1a hash. The signature is only used as an opaque
// change-detection token (equality compare), so a short hash beats embedding the
// full inputs + derived chunks as JSON.
function hashString(value: string): string {
  let hash = 0x811c9dc5;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(36);
}

function getOuterHeight(element: HTMLElement): number {
  const rect = element.getBoundingClientRect();
  const styles = window.getComputedStyle(element);
  const marginTop = Number.parseFloat(styles.marginTop || '0') || 0;
  const marginBottom = Number.parseFloat(styles.marginBottom || '0') || 0;
  return rect.height + marginTop + marginBottom;
}

function readItemMeta(element: HTMLElement): StaticFlowItemMeta {
  return {
    breakBefore: element.dataset.uhuuFlowBreakBefore === 'true',
    breakAfter: element.dataset.uhuuFlowBreakAfter === 'true',
    keepWithNext: parseKeepWithNext(element.dataset.uhuuFlowKeepWithNext),
    avoidBreakInside: element.dataset.uhuuFlowAvoidBreakInside === 'true',
    groupKey: element.dataset.uhuuFlowGroupKey,
  };
}

type BuildChunksOptions = {
  onZeroHeight?: () => void;
  onOversizedItem?: (key: string, height: number, availableHeight: number) => void;
};

function buildChunks(
  area: HTMLElement,
  flow: HTMLElement,
  options: BuildChunksOptions = {}
): StaticFlowMeasurement | null {
  const flowId = flow.dataset.uhuuFlowId;
  if (!flowId) return null;

  const itemElements = Array.from(flow.querySelectorAll<HTMLElement>('[data-uhuu-flow-item="true"]'));
  if (!itemElements.length) {
    return {
      flowId,
      chunks: [{ indexes: [], keys: [] }],
      signature: `${flowId}:empty`,
    };
  }

  const areaRect = area.getBoundingClientRect();
  const measuredAvailableHeight = areaRect.height || area.clientHeight;
  const hasAvailableHeight = Number.isFinite(measuredAvailableHeight) && measuredAvailableHeight > 0;
  const fallbackHeight = hasAvailableHeight
    ? measuredAvailableHeight
    : itemElements.reduce((sum, item) => sum + getOuterHeight(item), 0);

  const heights = itemElements.map(getOuterHeight);
  const metas = itemElements.map(readItemMeta);
  const keys = itemElements.map((item, index) => item.dataset.uhuuFlowKey || String(index));

  if (!hasAvailableHeight) {
    options.onZeroHeight?.();
  }

  if (hasAvailableHeight) {
    const oversizedIndex = heights.findIndex((height) => height > fallbackHeight);
    if (oversizedIndex >= 0) {
      options.onOversizedItem?.(keys[oversizedIndex], heights[oversizedIndex], fallbackHeight);
    }
  }

  const finalChunks: StaticFlowChunk[] = distributeFlowItems({
    heights,
    keys,
    metas,
    availableHeight: fallbackHeight,
  });
  const signature = hashString(JSON.stringify({
    version: 1,
    flowId,
    availableHeight: Math.round(fallbackHeight * 100) / 100,
    heights: heights.map((height) => Math.round(height * 100) / 100),
    keys,
    metas,
  }));

  return { flowId, chunks: finalChunks, signature };
}

export function FlowArea({ children, className = '', style }: FlowAreaProps) {
  const context = React.useContext(StaticFlowContext);
  const areaRef = React.useRef<HTMLDivElement>(null);
  const lastSignatureRef = React.useRef<string>('');
  const warnedMultipleFlowsRef = React.useRef(false);
  const warnedZeroHeightRef = React.useRef(false);
  const warnedOversizedItemsRef = React.useRef(new Set<string>());

  useIsoLayoutEffect(() => {
    if (context?.mode !== 'measure' || !context.registerMeasurement || !areaRef.current) {
      return;
    }

    const area = areaRef.current;
    let rafId = 0;
    let resizeObserver: ResizeObserver | null = null;
    lastSignatureRef.current = '';

    const scheduleMeasure = () => {
      window.cancelAnimationFrame(rafId);
      rafId = window.requestAnimationFrame(measure);
    };

    const observedItems = new Set<HTMLElement>();
    const observeFlowItems = () => {
      if (!resizeObserver) return;

      for (const item of Array.from(observedItems)) {
        if (!area.contains(item)) {
          resizeObserver.unobserve(item);
          observedItems.delete(item);
        }
      }

      area
        .querySelectorAll<HTMLElement>('[data-uhuu-flow-item="true"]')
        .forEach((item) => {
          if (observedItems.has(item)) return;
          observedItems.add(item);
          resizeObserver?.observe(item);
        });
    };

    const measure = () => {
      observeFlowItems();

      const flows = area.querySelectorAll<HTMLElement>('[data-uhuu-flow="true"]');
      if (flows.length > 1 && !warnedMultipleFlowsRef.current && isDev()) {
        warnedMultipleFlowsRef.current = true;
        console.warn(
          '[uhuu-components] Static.FlowArea supports one Static.Flow child. ' +
          'Additional Static.Flow elements in the same area are ignored. Use one FlowArea per flow region.'
        );
      }

      const flow = flows[0];
      if (!flow) return;

      const measurement = buildChunks(area, flow, {
        onZeroHeight: () => {
          if (warnedZeroHeightRef.current || !isDev()) return;
          warnedZeroHeightRef.current = true;
          console.warn(
            '[uhuu-components] Static.FlowArea has flow items but no measurable height. ' +
            'Give the area an explicit height or use a constrained flex layout such as flex-1 min-h-0.'
          );
        },
        onOversizedItem: (key, height, availableHeight) => {
          if (warnedOversizedItemsRef.current.has(key) || !isDev()) return;
          warnedOversizedItemsRef.current.add(key);
          console.warn(
            `[uhuu-components] Static.Flow item "${key}" is taller than its FlowArea ` +
            `(${Math.round(height)}px > ${Math.round(availableHeight)}px). ` +
            'V1 can only move whole items, so split this item if it must fit within a page.'
          );
        },
      });
      if (!measurement || measurement.signature === lastSignatureRef.current) return;

      lastSignatureRef.current = measurement.signature;
      context.registerMeasurement?.(measurement);
    };

    resizeObserver = new ResizeObserver(scheduleMeasure);
    resizeObserver.observe(area);
    observeFlowItems();
    scheduleMeasure();

    const mutationObserver = new MutationObserver(() => {
      observeFlowItems();
      scheduleMeasure();
    });
    mutationObserver.observe(area, {
      attributes: true,
      attributeFilter: [
        'class',
        'style',
        'data-uhuu-flow',
        'data-uhuu-flow-id',
        'data-uhuu-flow-item',
        'data-uhuu-flow-key',
        'data-uhuu-flow-break-before',
        'data-uhuu-flow-break-after',
        'data-uhuu-flow-keep-with-next',
        'data-uhuu-flow-avoid-break-inside',
        'data-uhuu-flow-group-key',
      ],
      characterData: true,
      childList: true,
      subtree: true,
    });

    return () => {
      window.cancelAnimationFrame(rafId);
      resizeObserver?.disconnect();
      mutationObserver.disconnect();
    };
  }, [context]);

  return (
    <div ref={areaRef} className={className} style={style} data-uhuu-flow-area="true">
      {children}
    </div>
  );
}

type FlowPageProps = {
  children: React.ReactNode;
  header?: React.ReactNode;
  footer?: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
  flowAreaClassName?: string;
  flowAreaStyle?: React.CSSProperties;
};

export function FlowPage({
  children,
  header,
  footer,
  className = '',
  style,
  flowAreaClassName = '',
  flowAreaStyle,
}: FlowPageProps) {
  return (
    <div
      className={`h-full w-full flex flex-col ${className}`}
      style={style}
      data-uhuu-flow-page="true"
    >
      {header}
      <FlowArea
        className={`flex-1 min-h-0 ${flowAreaClassName}`}
        style={flowAreaStyle}
      >
        {children}
      </FlowArea>
      {footer}
    </div>
  );
}

type FlowProps<TItem, TType extends string = DefaultFlowItemType<TItem>> = {
  id: string;
  items: TItem[];
  getKey: (item: TItem, index: number) => React.Key;
  renderItem: (item: TItem, index: number) => React.ReactNode;
  getItemMeta?: (item: TItem, index: number) => StaticFlowItemMeta | undefined;
  metaDefaults?: Partial<Record<TType, StaticFlowItemMeta>>;
  getItemType?: (item: TItem, index: number) => TType | undefined;
  className?: string;
  itemClassName?: string | ((item: TItem, index: number) => string | undefined);
};

export function Flow<TItem, TType extends string = DefaultFlowItemType<TItem>>({
  id,
  items,
  getKey,
  renderItem,
  getItemMeta,
  metaDefaults,
  getItemType: resolveItemType,
  className = '',
  itemClassName,
}: FlowProps<TItem, TType>) {
  const context = React.useContext(StaticFlowContext);
  const chunks = context?.chunksByFlowId?.[id];
  const rawVisibleIndexes =
    context?.mode === 'visible' && chunks
      ? (chunks[context.pageIndex]?.indexes ?? [])
      : context?.mode === 'visible' && context.pageIndex > 0
        ? []
        : items.map((_, index) => index);

  // Guard against stale chunk indexes when items shrink (e.g. rowCount decreased before remeasure)
  const visibleIndexes = rawVisibleIndexes.filter((idx) => (
    Number.isInteger(idx) && idx >= 0 && idx < items.length
  ));

  React.useEffect(() => {
    if (!isDev() || !metaDefaults || !Object.keys(metaDefaults).length || !items.length) {
      return;
    }

    const warningKey = `${id}:${Object.keys(metaDefaults).join('|')}`;
    if (warnedMetaDefaultsWithoutType.has(warningKey)) return;

    const hasResolvableType = items.some((item, index) => (
      Boolean(resolveItemType?.(item, index) ?? getItemType(item))
    ));
    if (hasResolvableType) return;

    warnedMetaDefaultsWithoutType.add(warningKey);
    console.warn(
      `[uhuu-components] Static.Flow "${id}" received metaDefaults, but no item type could be resolved. ` +
      'Add a type field to each item or pass getItemType so defaults can be applied.'
    );
  }, [id, items, metaDefaults, resolveItemType]);

  return (
    <div
      className={className}
      data-uhuu-flow="true"
      data-uhuu-flow-id={id}
    >
      {visibleIndexes.map((itemIndex) => {
        const item = items[itemIndex];
        if (item === undefined) return null;

        const key = getKey(item, itemIndex);
        const type = resolveItemType?.(item, itemIndex) ?? (getItemType(item) as TType | undefined);
        const meta = mergeItemMeta(
          type ? metaDefaults?.[type] : undefined,
          getItemMeta?.(item, itemIndex)
        );
        const resolvedItemClassName =
          typeof itemClassName === 'function'
            ? itemClassName(item, itemIndex)
            : itemClassName;

        return (
          <div
            key={key}
            className={resolvedItemClassName}
            style={{ display: 'flow-root' }}
            data-uhuu-flow-item="true"
            data-uhuu-flow-key={String(key)}
            data-uhuu-flow-index={itemIndex}
            data-uhuu-flow-break-before={meta.breakBefore ? 'true' : undefined}
            data-uhuu-flow-break-after={meta.breakAfter ? 'true' : undefined}
            data-uhuu-flow-keep-with-next={serializeKeepWithNext(meta.keepWithNext)}
            data-uhuu-flow-avoid-break-inside={meta.avoidBreakInside ? 'true' : undefined}
            data-uhuu-flow-group-key={meta.groupKey}
          >
            {renderItem(item, itemIndex)}
          </div>
        );
      })}
    </div>
  );
}
